import React from 'react';
import { Link } from 'react-router-dom';

const lenses = [
  {
    roman: 'I',
    title: 'Western Medicine',
    desc: 'An MD from Emory and years of clinical training give Fayzan a rigorous, biology-grounded lens on how physiology shapes cognition, behavior, and decision-making under pressure.',
    bg: 'linear-gradient(135deg, #431407 0%, #7c2d12 100%)',
  },
  {
    roman: 'II',
    title: 'Executive Coaching',
    desc: 'Thousands of hours mapping behavioral patterns, navigating organizational dynamics, and unlocking leadership capacity in high-stakes environments. PCC certified through the ICF.',
    bg: 'linear-gradient(135deg, #1c0f00 0%, #92400e 100%)',
  },
  {
    roman: 'III',
    title: 'Technology & Business',
    desc: 'As a former Google product leader and biotech operator, Fayzan understands the pressures of high-growth environments firsthand — and brings that experience directly into the coaching relationship.',
    bg: 'linear-gradient(135deg, #2d1b00 0%, #78350f 100%)',
  },
];

const credentials = [
  { label: 'Education', value: 'MD, Emory University School of Medicine' },
  { label: 'Certification', value: 'PCC — International Coaching Federation' },
  { label: 'Experience', value: 'Product Leader at Google · Series C Biotech' },
  { label: 'Practice', value: '1,000+ coaching hours with high performers' },
];

export default function About() {
  return (
    <div>
      {/* ── HERO ── */}
      <section style={{
        minHeight: '100vh',
        display: 'grid',
        gridTemplateColumns: '1fr 1fr',
        overflow: 'hidden',
      }} className="about-hero-grid">
        {/* Left text */}
        <div style={{
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'flex-end',
          padding: '100px 56px 80px',
          position: 'relative',
          background: 'linear-gradient(135deg, #0c0800 0%, #1a0e00 100%)',
        }}>
          <div style={{
            position: 'absolute', bottom: '25%', left: '20%',
            width: '300px', height: '300px',
            background: 'radial-gradient(circle, rgba(245,158,11,0.15) 0%, transparent 70%)',
          }} />
          <div style={{ position: 'relative' }}>
            <span className="label">About</span>
            <h1 style={{ fontSize: 'clamp(34px, 4.5vw, 60px)', fontWeight: 400, marginBottom: '14px' }}>
              Fayzan Rab
            </h1>
            <p style={{ fontSize: '14px', color: 'var(--text-3)', letterSpacing: '0.02em' }}>
              MD, Emory University · PCC Certified · Former Google
            </p>
          </div>
        </div>

        {/* Right portrait */}
        <div style={{ position: 'relative', overflow: 'hidden' }}>
          <img
            src="/images/fayzan-closeup.jpeg"
            alt="Fayzan Rab"
            style={{ width: '100%', height: '100%', objectFit: 'cover', objectPosition: 'top center' }}
          />
          <div style={{
            position: 'absolute', inset: 0,
            background: 'linear-gradient(to right, rgba(12,8,0,0.35) 0%, transparent 40%)',
          }} />
          <div style={{
            position: 'absolute', bottom: 0, left: 0, right: 0,
            height: '35%',
            background: 'linear-gradient(to top, rgba(12,8,0,0.55) 0%, transparent 100%)',
          }} />
        </div>

        <style>{`
          @media (max-width: 768px) {
            .about-hero-grid { grid-template-columns: 1fr !important; min-height: auto !important; }
            .about-hero-grid > div:first-child { padding: 120px 28px 50px !important; min-height: 50vh; }
            .about-hero-grid > div:last-child { height: 55vw; min-height: 300px; }
          }
        `}</style>
      </section>

      {/* ── STORY ── */}
      <section className="section">
        <div className="container">
          <div style={{ display: 'grid', gridTemplateColumns: '1.25fr 1fr', gap: '72px', alignItems: 'start' }} className="two-col">
            {/* Story */}
            <div>
              <span className="label">The Story</span>
              <h2 style={{ fontSize: 'clamp(24px, 2.8vw, 36px)', marginBottom: '24px' }}>
                I was doing everything right — and it wasn't enough.
              </h2>
              <p style={{ color: 'var(--text-2)', lineHeight: '1.82', marginBottom: '16px', fontSize: '15px' }}>
                I worked in Silicon Valley as a product leader at Google and a Series C biotech startup. Successful by most measures. But unfulfilled and unclear on what the highest utilization of my gifts would actually look like.
              </p>
              <p style={{ color: 'var(--text-2)', lineHeight: '1.82', marginBottom: '16px', fontSize: '15px' }}>
                I tried many things before stumbling into executive coaching — where I saw the potential to create something unique to my voice and craft. I went to medical school at Emory and accumulated thousands of hours coaching high performers.
              </p>
              <p style={{ color: 'var(--text-2)', lineHeight: '1.82', fontSize: '15px' }}>
                The goal was never just to help people get unstuck. It was to synthesize the best of medicine and coaching — to fully unleash what each person is already capable of.
              </p>
            </div>

            {/* Credentials card */}
            <div style={{
              background: 'linear-gradient(135deg, rgba(245,158,11,0.08) 0%, rgba(234,108,30,0.05) 100%)',
              border: '1px solid var(--border-2)',
              borderRadius: '18px',
              padding: '32px',
            }}>
              <div style={{
                width: '52px', height: '52px',
                borderRadius: '12px',
                background: 'linear-gradient(135deg, #f59e0b, #ea6c1e)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: '20px',
                fontFamily: "'DM Serif Display', serif",
                color: '#fff',
                marginBottom: '28px',
                boxShadow: '0 0 24px rgba(245,158,11,0.3)',
              }}>FR</div>

              {credentials.map(({ label, value }, i) => (
                <div key={label} style={{
                  paddingBottom: i < credentials.length - 1 ? '18px' : 0,
                  marginBottom: i < credentials.length - 1 ? '18px' : 0,
                  borderBottom: i < credentials.length - 1 ? '1px solid var(--border)' : 'none',
                }}>
                  <span style={{
                    display: 'block',
                    fontSize: '10px', fontWeight: 700, letterSpacing: '0.15em',
                    textTransform: 'uppercase', color: 'var(--amber)',
                    marginBottom: '5px',
                  }}>{label}</span>
                  <span style={{ fontSize: '14px', color: 'var(--text)', lineHeight: '1.5' }}>{value}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* ── TEDx image break ── */}
      <section style={{ padding: '0 28px 96px' }}>
        <div className="container">
          <div style={{ position: 'relative', borderRadius: '18px', overflow: 'hidden' }}>
            <img
              src="/images/fayz-ted.jpg"
              alt="Fayzan Rab speaking at TEDxEmory"
              style={{ width: '100%', height: '400px', objectFit: 'cover', objectPosition: 'center 25%' }}
            />
            <div style={{
              position: 'absolute', inset: 0,
              background: 'linear-gradient(to top, rgba(12,8,0,0.7) 0%, transparent 60%)',
            }} />
            <p style={{
              position: 'absolute', bottom: '28px', left: '32px',
              fontSize: '12px', fontWeight: 600, letterSpacing: '0.14em',
              textTransform: 'uppercase', color: 'rgba(255,255,255,0.6)',
            }}>TEDxEmory Speaker</p>
          </div>
        </div>
      </section>

      {/* ── THREE LENSES ── */}
      <section style={{ padding: '0 0 96px' }}>
        <div className="container">
          <span className="label" style={{ display: 'block', textAlign: 'center' }}>Three Lenses</span>
          <h2 style={{ fontSize: 'clamp(24px, 3vw, 38px)', textAlign: 'center', marginBottom: '44px' }}>
            What informs the work
          </h2>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '16px' }} className="three-col">
            {lenses.map(({ roman, title, desc, bg }) => (
              <div key={title} style={{
                background: bg,
                borderRadius: '16px',
                padding: '32px 26px',
                position: 'relative',
                overflow: 'hidden',
                border: '1px solid rgba(245,158,11,0.12)',
                transition: 'transform 0.25s ease, box-shadow 0.25s ease',
              }}
              onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-5px)'; e.currentTarget.style.boxShadow = '0 20px 50px rgba(245,158,11,0.15)'; }}
              onMouseLeave={e => { e.currentTarget.style.transform = 'none'; e.currentTarget.style.boxShadow = 'none'; }}
              >
                <div style={{
                  position: 'absolute', bottom: '-4px', right: '16px',
                  fontSize: '76px', fontFamily: "'DM Serif Display', serif",
                  color: 'rgba(255,255,255,0.06)', lineHeight: 1, userSelect: 'none',
                }}>{roman}</div>
                <h3 style={{
                  fontFamily: "'DM Serif Display', serif",
                  fontSize: '20px', fontWeight: 400,
                  color: '#fff', marginBottom: '12px',
                }}>{title}</h3>
                <p style={{ fontSize: '14px', lineHeight: '1.75', color: 'rgba(255,255,255,0.6)' }}>{desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── LOGO STRIP ── */}
      <div className="logo-strip">
        <div className="container">
          <div className="logo-strip-inner">
            {['MD, Emory University', 'PCC Certified (ICF)', 'Google', 'TEDx Speaker'].map(item => (
              <span key={item} className="logo-strip-item">{item}</span>
            ))}
          </div>
        </div>
      </div>

      {/* ── CTA ── */}
      <section style={{ padding: '80px 28px' }}>
        <div className="container" style={{ textAlign: 'center' }}>
          <h2 style={{ fontSize: 'clamp(22px, 2.8vw, 34px)', marginBottom: '12px' }}>
            Ready to explore working together?
          </h2>
          <p style={{ color: 'var(--text-2)', marginBottom: '28px', fontSize: '15px' }}>
            Reach out to schedule an introductory conversation.
          </p>
          <Link to="/contact" className="btn btn-primary">Get in touch</Link>
        </div>
      </section>
    </div>
  );
}
